#[inline]
fn hash_mnemonic(mnemonic: &str) -> u64 {
let mut hash = 0xcbf2_9ce4_8422_2325u64 ^ MNEMONIC_HASH_SEED;
for byte in mnemonic.as_bytes() {
hash ^= u64::from(*byte);
hash = hash.wrapping_mul(0x100_0000_01b3);
}
hash
}

pub(crate) fn mnemonic_id_from_str(mnemonic: &str) -> Option<MnemonicId> {
let slot = (hash_mnemonic(mnemonic) as usize) & MNEMONIC_HASH_MASK;
let entry = *MNEMONIC_HASH_TABLE.get(slot)?;
if entry == u16::MAX {
return None;
}
let index = usize::from(entry);
let dispatch = *MNEMONIC_DISPATCH.get(index)?;
if dispatch.name == mnemonic {
Some(MnemonicId(entry))
} else {
None
}
}

pub(crate) fn mnemonic_name(id: MnemonicId) -> Option<&'static str> {
let entry = *MNEMONIC_DISPATCH.get(usize::from(id.0))?;
Some(entry.name)
}

pub(crate) fn specs_for_mnemonic_id(id: MnemonicId) -> Option<&'static [EncodingSpec]> {
let entry = *MNEMONIC_DISPATCH.get(usize::from(id.0))?;
let start = usize::from(entry.spec_start);
let len = usize::from(entry.spec_len);
Some(&SPECS[start..start + len])
}

#[derive(Debug, Copy, Clone, PartialEq, Eq)]
pub(crate) enum ShapeVariantMatch {
Unique(VariantId),
Ambiguous,
}

#[inline]
fn lookup_shape_dispatch_entry(id: MnemonicId, shape_key: u128) -> Option<ShapeDispatchEntry> {
let entry = *MNEMONIC_DISPATCH.get(usize::from(id.0))?;
let shape_start = usize::from(entry.shape_start);
let shape_end = shape_start + usize::from(entry.shape_len);
let shapes = &SHAPE_DISPATCH[shape_start..shape_end];
let mut left = 0usize;
let mut right = shapes.len();
while left < right {
let mid = left + ((right - left) >> 1);
let probe = shapes[mid].key;
if probe < shape_key {
left = mid + 1;
continue;
}
if probe > shape_key {
right = mid;
continue;
}
return Some(shapes[mid]);
}
None
}

pub(crate) fn variant_match_for_shape(id: MnemonicId, shape_key: u128) -> Option<ShapeVariantMatch> {
let entry = lookup_shape_dispatch_entry(id, shape_key)?;
let start = usize::from(entry.start);
let len = usize::from(entry.len);
if len == 1 {
return Some(ShapeVariantMatch::Unique(SHAPE_VARIANT_IDS[start]));
}
Some(ShapeVariantMatch::Ambiguous)
}

#[allow(dead_code)]
pub(crate) fn variants_for_shape(id: MnemonicId, shape_key: u128) -> Option<&'static [VariantId]> {
let entry = lookup_shape_dispatch_entry(id, shape_key)?;
let start = usize::from(entry.start);
let len = usize::from(entry.len);
Some(&SHAPE_VARIANT_IDS[start..start + len])
}

pub(crate) fn encode_variant(id: VariantId, operands: &[Operand]) -> Result<InstructionCode, EncodeError> {
let index = usize::from(id.0);
let spec = SPECS.get(index).ok_or(EncodeError::NoMatchingVariant)?;
jit_core::encode_by_spec_operands(spec, operands)
}

pub(crate) fn spec_for_variant(id: VariantId) -> Option<&'static EncodingSpec> {
SPECS.get(usize::from(id.0))
}

pub(crate) fn specs_for_mnemonic(mnemonic: &str) -> Option<&'static [EncodingSpec]> {
let id = mnemonic_id_from_str(mnemonic)?;
specs_for_mnemonic_id(id)
}
pub(crate) fn mnemonic_name_const<const MNEMONIC: u16>() -> Option<&'static str> {
let index = MNEMONIC as usize;
let entry = *MNEMONIC_DISPATCH.get(index)?;
Some(entry.name)
}

pub(crate) fn specs_for_mnemonic_id_const<const MNEMONIC: u16>() -> Option<&'static [EncodingSpec]> {
let index = MNEMONIC as usize;
let entry = *MNEMONIC_DISPATCH.get(index)?;
let start = usize::from(entry.spec_start);
let len = usize::from(entry.spec_len);
Some(&SPECS[start..start + len])
}

pub(crate) fn spec_for_variant_const<const VARIANT: u16>() -> Option<&'static EncodingSpec> {
SPECS.get(VARIANT as usize)
}

pub(crate) fn encode_variant_const<const VARIANT: u16>(operands: &[Operand]) -> Result<InstructionCode, EncodeError> {
let spec = spec_for_variant_const::<VARIANT>().ok_or(EncodeError::NoMatchingVariant)?;
jit_core::encode_by_spec_operands(spec, operands)
}
